import{_ as i,C as o,o as c,c as s,j as t,a as d,E as a,ag as l}from"./chunks/framework.HG0H2VLS.js";const x=JSON.parse('{"title":"DatePicker","description":"","frontmatter":{},"headers":[],"relativePath":"components/date-picker.md","filePath":"components/date-picker.md"}'),h={name:"components/date-picker.md"},p={id:"datepicker",tabindex:"-1"};function g(m,e,u,b,f,y){const r=o("Badge"),n=o("ComponentDemo");return c(),s("div",null,[e[3]||(e[3]=t("hr",null,null,-1)),e[4]||(e[4]=t("h2",{id:"title-datepicker",tabindex:"-1"},[d("title: DatePicker "),t("a",{class:"header-anchor",href:"#title-datepicker","aria-label":'Permalink to "title: DatePicker"'},"​")],-1)),t("h1",p,[e[0]||(e[0]=d("DatePicker ",-1)),a(r,{type:"info",text:"Design System"}),e[1]||(e[1]=d()),e[2]||(e[2]=t("a",{class:"header-anchor",href:"#datepicker","aria-label":'Permalink to "DatePicker <Badge type="info" text="Design System" />"'},"​",-1))]),e[5]||(e[5]=t("blockquote",null,[t("p",null,"functional vanilla-JS calendar")],-1)),a(n,{src:"/demos/src/components/DatePicker/DatePicker.html"}),e[6]||(e[6]=l('<h2 id="variant-matrix-7-property-1-values-→-modes-views-of-one-calendar" tabindex="-1">Variant matrix (7 Property 1 values → modes/views of one calendar) <a class="header-anchor" href="#variant-matrix-7-property-1-values-→-modes-views-of-one-calendar" aria-label="Permalink to &quot;Variant matrix (7 Property 1 values → modes/views of one calendar)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Node ID</th><th>Property 1</th><th>Represented as</th><th>Built</th></tr></thead><tbody><tr><td>3039:8754</td><td>Single Date</td><td><code>data-mode=&quot;single&quot;</code> + Input trigger + popover; footer &quot;Selected: …&quot;</td><td>✅</td></tr><tr><td>3039:8755</td><td>No selection (today highlighted)</td><td>inline, no selection → today = <code>--today</code>; footer hidden</td><td>✅</td></tr><tr><td>3039:8757</td><td>With disabled past dates</td><td><code>data-disable-past</code> → <code>--disabled</code> (opacity .5) on past days</td><td>✅</td></tr><tr><td>3039:8759</td><td>Date Range Single Month</td><td><code>data-mode=&quot;range&quot;</code> → <code>--range-start/-end/-in-range</code></td><td>✅</td></tr><tr><td>3039:8760</td><td>Date Range Dual Month</td><td><code>data-mode=&quot;range&quot; data-months=&quot;2&quot;</code> — two month panels, prev on left / next on right</td><td>✅</td></tr><tr><td>3039:8758</td><td>Month Selector</td><td>drill-down <code>view=months</code>; selected month = brand fill, current month = <code>--current</code></td><td>✅</td></tr><tr><td>3039:8756</td><td>Year Selector</td><td>drill-down <code>view=years</code>; current year = <code>--current</code> (grey bg + brand bold)</td><td>✅</td></tr></tbody></table><p><strong>These are not independent components</strong> — Month/Year selectors are sub-views reached by clicking the header title (day-view title → months; months-view title → years). Range single/dual are the same calendar with <code>mode=range</code> and 1 or 2 panels.</p><h2 id="interaction-model-confirmed-with-user-2026-07-07" tabindex="-1">Interaction model (confirmed with user, 2026-07-07) <a class="header-anchor" href="#interaction-model-confirmed-with-user-2026-07-07" aria-label="Permalink to &quot;Interaction model (confirmed with user, 2026-07-07)&quot;">​</a></h2><ul><li><strong>Scope:</strong> fully functional vanilla-JS date picker (<code>DatePicker.js</code>), auto-inits <code>[data-datepicker]</code>.</li><li><strong>One picker, drill-down:</strong> single vs range is a config (<code>data-mode</code>); month/year selectors are reached by clicking the header title and return to the day grid on selection.</li><li><strong>Single select:</strong> click a day → sets selection, writes the field (<code>11 Mar 2026</code>), closes the popover.</li><li><strong>Range select:</strong> first click sets start, second sets end (auto-normalised if reversed); a third click starts a new range. Field shows <code>9 Mar — 21 Mar 2026</code>.</li><li><strong>Nav:</strong> prev/next shifts month (day view), year (month view), or 12-year page (year view).</li><li><strong>Today:</strong> jumps the view to the current month; in single mode also selects today.</li><li><strong>Popover:</strong> opens on field focus/click or calendar-icon click; closes on outside-click or Esc.</li><li>Week starts <strong>Monday</strong> (Mo Tu We Th Fr Sa Su).</li></ul><h2 id="token-gaps-decisions" tabindex="-1">Token Gaps / Decisions <a class="header-anchor" href="#token-gaps-decisions" aria-label="Permalink to &quot;Token Gaps / Decisions&quot;">​</a></h2><ul><li><strong>None.</strong> Every colour, spacing, radius, and type value maps to an existing <code>--ai-*</code> token.</li><li>Calendar shadow: Figma specifies <code>0 0 10px rgba(0,0,0,.05), 0 2px 1px rgba(0,0,0,.1)</code>; used the standard <code>--ai-shadow-lg</code> popover token (<code>0 0 20px …, 0 2px 2px …</code>) — optical, within tolerance.</li></ul><h2 id="css-classes" tabindex="-1">CSS Classes <a class="header-anchor" href="#css-classes" aria-label="Permalink to &quot;CSS Classes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Figma element</th><th>CSS class</th></tr></thead><tbody><tr><td>Calendar surface</td><td><code>.datepicker__calendar</code> (<code>--popover</code> anchored + hidden until <code>.datepicker--open</code>; <code>--dual</code> two panels)</td></tr><tr><td>Row of month panels</td><td><code>.datepicker__months</code></td></tr><tr><td>One month panel</td><td><code>.datepicker__month</code></td></tr><tr><td>Header (title + nav)</td><td><code>.datepicker__header</code></td></tr><tr><td>Month/Year title (drill-down trigger)</td><td><code>.datepicker__title</code></td></tr><tr><td>Prev/next nav buttons</td><td><code>.datepicker__nav</code> / <code>.datepicker__nav-btn</code></td></tr><tr><td>Weekday row</td><td><code>.datepicker__weekdays</code> / <code>.datepicker__weekday</code></td></tr><tr><td>Day grid</td><td><code>.datepicker__grid</code> (7-col); <code>--months</code> / <code>--years</code> (3-col)</td></tr><tr><td>Day/month/year cell</td><td><code>.datepicker__cell</code> + state modifiers below</td></tr><tr><td>Footer</td><td><code>.datepicker__footer</code> (hidden when no selection)</td></tr><tr><td>Selected summary</td><td><code>.datepicker__selected</code></td></tr><tr><td>Today link</td><td><code>.datepicker__today-btn</code></td></tr><tr><td>Trigger field</td><td>Composes the <strong>Input</strong> component (<code>.input</code> / <code>.input__wrap</code> / <code>.input__control</code>) + <code>.datepicker__field-icon</code></td></tr></tbody></table><h3 id="cell-state-modifiers" tabindex="-1">Cell state modifiers <a class="header-anchor" href="#cell-state-modifiers" aria-label="Permalink to &quot;Cell state modifiers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Modifier</th><th>Treatment</th><th>Token</th></tr></thead><tbody><tr><td>(base) current-month day</td><td>text-primary regular</td><td><code>--ai-text-primary</code></td></tr><tr><td><code>--muted</code></td><td>adjacent-month day</td><td><code>--ai-text-contrast</code></td></tr><tr><td><code>--today</code></td><td>grey bg + brand bold</td><td><code>--ai-surface-minimal</code> + <code>--ai-text-brand</code> + <code>--ai-font-bold</code></td></tr><tr><td><code>--selected</code></td><td>brand fill + white semibold</td><td><code>--ai-surface-brand</code> + <code>--ai-text-invert</code> + <code>--ai-font-semibold</code></td></tr><tr><td><code>--range-start</code> / <code>--range-end</code></td><td>brand fill, rounded on one side only</td><td><code>--ai-surface-brand</code> + <code>--ai-text-invert</code></td></tr><tr><td><code>--in-range</code></td><td>soft band + brand medium, square</td><td><code>--ai-surface-brand-soft-extra</code> + <code>--ai-text-brand</code> + <code>--ai-font-medium</code></td></tr><tr><td><code>--disabled</code></td><td>50% opacity, not-allowed</td><td><code>opacity: 0.5</code> + <code>--ai-text-contrast</code></td></tr><tr><td><code>--current</code> (month/year grid)</td><td>same as <code>--today</code></td><td><code>--ai-surface-minimal</code> + <code>--ai-text-brand</code> bold</td></tr><tr><td>hover (enabled, unselected)</td><td>subtle grey</td><td><code>--ai-surface-minimal</code></td></tr></tbody></table><h2 id="token-mapping" tabindex="-1">Token Mapping <a class="header-anchor" href="#token-mapping" aria-label="Permalink to &quot;Token Mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Property</th><th>Token</th></tr></thead><tbody><tr><td>Calendar bg / border / radius</td><td><code>--ai-surface-primary</code> / <code>--ai-border-secondary</code> (1px) / <code>--ai-radius-md</code></td></tr><tr><td>Calendar shadow</td><td><code>--ai-shadow-lg</code> (Figma <code>0 0 10px .05, 0 2px 1px .1</code> — mapped to the standard card/popover token)</td></tr><tr><td>Calendar padding</td><td><code>--ai-spacing-5</code> (16px)</td></tr><tr><td>Month panel gap (dual)</td><td><code>--ai-spacing-6</code> (24px)</td></tr><tr><td>Cell size</td><td><code>--ai-spacing-7</code> (32px), grid gap <code>--ai-spacing-1</code> (4px)</td></tr><tr><td>Cell radius</td><td><code>--ai-radius-md</code></td></tr><tr><td>Day / title font</td><td><code>--ai-font-title</code> <code>--ai-font-fixed-xs</code> (14px) <code>--ai-leading-xs</code></td></tr><tr><td>Weekday / footer / month-year-cell font</td><td><code>--ai-font-fixed-xxs</code> (12px)</td></tr><tr><td>Nav / field icon</td><td><code>--ai-icon-size-sm</code> (16px), <code>--ai-icon-contrast</code></td></tr><tr><td>Footer border / padding</td><td><code>--ai-border-secondary</code> top, <code>--ai-spacing-4</code> (12px)</td></tr></tbody></table><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li><strong>Icons (Lucide):</strong> header nav = <code>chevron-left</code> / <code>chevron-right</code>; trigger field = <code>calendar</code>.</li><li><strong>Trigger reuses the Input component</strong> (<code>../Input/Input.css</code>) rather than a bespoke field — the Figma layer was named &quot;Text Input&quot; (not the Input component instance) but is token-identical.</li><li><strong>Footer visibility:</strong> Figma&#39;s &quot;No selection&quot; variant has no footer, so the footer is hidden until a date/range is selected.</li><li><strong>Today-in-range:</strong> a day that is both today and inside a range keeps its <strong>bold</strong> weight (Figma shows day 11 bold on the soft band while neighbours are medium).</li><li><code>new Date()</code> is used for &quot;today&quot; — runs in the browser, so real current date drives the highlight.</li><li>Dual-month range hides the redundant nav arrow on each panel (prev only on left, next only on right).</li></ul><h2 id="figma" tabindex="-1">Figma <a class="header-anchor" href="#figma" aria-label="Permalink to &quot;Figma&quot;">​</a></h2><p><a href="https://www.figma.com/design/Lus07xi8pPXLN87sQIyrEt/Affino-AI---Design-System?node-id=3039-8761" target="_blank" rel="noreferrer">Open in Figma</a></p>',17))])}const v=i(h,[["render",g]]);export{x as __pageData,v as default};
